#!/usr/bin/env node
// Generates the site's "mandala" chapter/review art: a ring of one petal
// motif (<use> + rotate) around a hand-authored center icon, on a dark
// radial-gradient background — see CLAUDE.md > Images > "Guide chapter art
// is hand-authored SVG". Only the frame (gradient, rings, petal ring) is
// generated; the center icon per item stays hand-drawn markup, same as the
// original 11 guide-chapter SVGs (those predate this script and are not
// regenerated by it).
//
// Config lives in SETS below, one named set per content type. Add a new set
// (e.g. "epics") by adding a key — nothing else changes.
//
// Usage:
//   node scripts/generate-mandala.mjs <set> [--only=slug1,slug2]
//   node scripts/generate-mandala.mjs --list

import { writeFileSync, mkdirSync } from 'node:fs'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'

const ROOT = join(dirname(fileURLToPath(import.meta.url)), '..')
const SIZE = 800
const CENTER = SIZE / 2

function renderMandala({
  bg,
  stroke,
  petalCount,
  centerIcon,
  outerRadius = 330,
  innerRadius = outerRadius - 150,
  rings = [outerRadius + 20, Math.round((outerRadius + innerRadius) / 2 + 15)],
  petalOpacity = 0.4,
  petalStrokeWidth = 1.6,
  ringOpacity = 0.28,
}) {
  const midRadius = (outerRadius + innerRadius) / 2
  // Cap petal half-width to a fraction of the gap between adjacent petals at
  // their widest point, so they read as separate petals instead of overlapping.
  const arcSpacing = 2 * outerRadius * Math.sin(Math.PI / petalCount)
  const halfWidth = Math.round(Math.min(48, Math.max(14, arcSpacing * 0.42)))
  const baseY = Math.round(CENTER - innerRadius)
  const tipY = Math.round(CENTER - outerRadius)
  const midY = (CENTER - midRadius).toFixed(1)
  const petalPath = `M${CENTER},${baseY} Q${CENTER + halfWidth},${midY} ${CENTER},${tipY} Q${CENTER - halfWidth},${midY} ${CENTER},${baseY} Z`

  const petals = Array.from(
    { length: petalCount },
    (_, i) => `  <use href="#petal" transform="rotate(${(360 / petalCount) * i} ${CENTER} ${CENTER})"/>`
  ).join('\n')

  const ringCircles = rings
    .map(
      (r) =>
        `  <circle cx="${CENTER}" cy="${CENTER}" r="${r}" fill="none" stroke="${stroke}" stroke-width="1" opacity="${ringOpacity}"/>`
    )
    .join('\n')

  return `<svg viewBox="0 0 ${SIZE} ${SIZE}" xmlns="http://www.w3.org/2000/svg">
  <defs>
    <radialGradient id="bg" cx="50%" cy="46%" r="72%">
      <stop offset="0%" stop-color="${bg[0]}"/>
      <stop offset="55%" stop-color="${bg[1]}"/>
      <stop offset="100%" stop-color="${bg[2]}"/>
    </radialGradient>
    <path id="petal" d="${petalPath}" fill="none" stroke="${stroke}" stroke-width="${petalStrokeWidth}" opacity="${petalOpacity}"/>
  </defs>
  <rect width="${SIZE}" height="${SIZE}" fill="url(#bg)"/>
${ringCircles}
${petals}
  <g transform="translate(${CENTER},${CENTER})">
${centerIcon.trim()}
  </g>
</svg>
`
}

