function main() {
  const [, , setName, ...rest] = process.argv

  if (!setName || setName === '--list') {
    console.log(`Available sets: ${Object.keys(SETS).join(', ')}`)
    for (const [name, set] of Object.entries(SETS)) {
      console.log(`  ${name}: ${set.items.length} item(s) -> ${set.outDir}/${set.prefix}-<slug>.svg`)
    }
    return
  }

  const set = SETS[setName]
  if (!set) {
    console.error(`Unknown set "${setName}". Available: ${Object.keys(SETS).join(', ')}`)
    process.exit(1)
  }

  const onlyArg = rest.find((a) => a.startsWith('--only='))
  const only = onlyArg ? new Set(onlyArg.slice('--only='.length).split(',')) : null

  const outDir = join(ROOT, set.outDir)
  mkdirSync(outDir, { recursive: true })

  let written = 0
  for (const item of set.items) {
    if (only && !only.has(item.slug)) continue
    const svg = renderMandala(item)
    const file = join(outDir, `${set.prefix}-${item.slug}.svg`)
    writeFileSync(file, svg)
    console.log(`wrote ${file}`)
    written++
  }
  if (written === 0) console.log(`Nothing written (set "${setName}" has no matching items).`)
}

main()
